import { EditorView } from "@codemirror/view";
import { HighlightStyle, syntaxHighlighting } from "@codemirror/language";
import { tags } from "@lezer/highlight";

/**
 * Dark editor theme matching the app's Tailwind design.
 * Uses gray-950 background, gray-100 text, JetBrains Mono font.
 */
export const editorTheme = EditorView.theme(
  {
    "&": {
      color: "#f3f4f6", // gray-100
      backgroundColor: "#030712", // gray-950
      fontFamily: '"JetBrains Mono", ui-monospace, SFMono-Regular, monospace',
      fontSize: "15px",
      height: "100%",
    },
    "&.cm-focused": {
      outline: "none",
    },
    ".cm-content": {
      caretColor: "#60a5fa", // blue-400
      padding: "1rem 0",
      maxWidth: "72ch",
      margin: "0 auto",
      lineHeight: "1.7",
    },
    ".cm-cursor, .cm-dropCursor": {
      borderLeftColor: "#60a5fa",
      borderLeftWidth: "2px",
    },
    ".cm-selectionBackground, &.cm-focused .cm-selectionBackground": {
      backgroundColor: "#1e3a5f",
    },
    ".cm-activeLine": {
      backgroundColor: "#0d1117",
    },
    ".cm-gutters": {
      backgroundColor: "#030712",
      color: "#4b5563", // gray-600
      border: "none",
      paddingRight: "8px",
    },
    ".cm-activeLineGutter": {
      backgroundColor: "#0d1117",
      color: "#9ca3af", // gray-400
    },
    ".cm-scroller": {
      overflow: "auto",
    },
    // Inline markdown rendering styles
    ".cm-header-1": {
      fontSize: "2em",
      fontWeight: "700",
      lineHeight: "1.3",
      color: "#f9fafb",
    },
    ".cm-header-2": {
      fontSize: "1.5em",
      fontWeight: "600",
      lineHeight: "1.4",
      color: "#f3f4f6",
    },
    ".cm-header-3": {
      fontSize: "1.25em",
      fontWeight: "600",
      lineHeight: "1.5",
      color: "#e5e7eb",
    },
    ".cm-header-4": {
      fontSize: "1.1em",
      fontWeight: "600",
      color: "#d1d5db",
    },
    ".cm-header-5": {
      fontSize: "1.05em",
      fontWeight: "600",
      color: "#d1d5db",
    },
    ".cm-header-6": {
      fontSize: "1em",
      fontWeight: "600",
      color: "#9ca3af",
    },

    // CriticMark decoration styles
    ".cm-criticmark-addition": {
      backgroundColor: "rgba(34, 197, 94, 0.15)", // green-500/15
      color: "#86efac", // green-300
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-deletion": {
      backgroundColor: "rgba(239, 68, 68, 0.15)", // red-500/15
      color: "#fca5a5", // red-300
      textDecoration: "line-through",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-substitution-old": {
      backgroundColor: "rgba(239, 68, 68, 0.15)",
      color: "#fca5a5",
      textDecoration: "line-through",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-substitution-new": {
      backgroundColor: "rgba(34, 197, 94, 0.15)",
      color: "#86efac",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-comment": {
      backgroundColor: "rgba(234, 179, 8, 0.15)", // yellow-500/15
      color: "#fde68a", // yellow-200
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-highlight": {
      backgroundColor: "rgba(168, 85, 247, 0.15)", // purple-500/15
      color: "#d8b4fe", // purple-300
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-delim": {
      color: "#4b5563", // gray-600 - dim the delimiters
      fontSize: "0.85em",
    },

    // Suggestion accept/reject action buttons
    ".cm-suggestion-actions": {
      display: "inline-flex",
      alignItems: "center",
      gap: "1px",
      marginLeft: "2px",
      verticalAlign: "middle",
      opacity: "0.6",
      transition: "opacity 0.15s ease",
    },
    ".cm-suggestion-actions:hover": {
      opacity: "1",
    },
    ".cm-suggestion-accept, .cm-suggestion-reject": {
      display: "inline-flex",
      alignItems: "center",
      justifyContent: "center",
      width: "18px",
      height: "18px",
      border: "none",
      borderRadius: "3px",
      cursor: "pointer",
      fontSize: "12px",
      lineHeight: "1",
      padding: "0",
      fontWeight: "bold",
      transition: "background-color 0.15s ease, color 0.15s ease",
    },
    ".cm-suggestion-accept": {
      backgroundColor: "rgba(34, 197, 94, 0.2)",
      color: "#86efac",
    },
    ".cm-suggestion-accept:hover": {
      backgroundColor: "rgba(34, 197, 94, 0.4)",
      color: "#bbf7d0",
    },
    ".cm-suggestion-reject": {
      backgroundColor: "rgba(239, 68, 68, 0.2)",
      color: "#fca5a5",
    },
    ".cm-suggestion-reject:hover": {
      backgroundColor: "rgba(239, 68, 68, 0.4)",
      color: "#fecaca",
    },

    // Remote cursor styles (y-codemirror.next overrides for dark theme)
    ".cm-ySelectionCaret": {
      position: "relative",
      borderLeft: "2px solid",
      borderRight: "none",
      marginLeft: "-1px",
      marginRight: "-1px",
      boxSizing: "border-box",
      display: "inline",
    },
    ".cm-ySelectionCaretDot": {
      borderRadius: "50%",
      position: "absolute",
      width: ".5em",
      height: ".5em",
      top: "-.25em",
      left: "-.25em",
      backgroundColor: "inherit",
      transition: "transform .3s ease-in-out",
      boxSizing: "border-box",
    },
    ".cm-ySelectionCaret:hover > .cm-ySelectionCaretDot": {
      transformOrigin: "bottom center",
      transform: "scale(0)",
    },
    ".cm-ySelectionInfo": {
      position: "absolute",
      top: "-1.2em",
      left: "-1px",
      fontSize: ".7em",
      fontFamily: '"JetBrains Mono", ui-monospace, SFMono-Regular, monospace',
      fontStyle: "normal",
      fontWeight: "600",
      lineHeight: "normal",
      userSelect: "none",
      color: "#030712",
      paddingLeft: "4px",
      paddingRight: "4px",
      paddingTop: "1px",
      paddingBottom: "1px",
      borderRadius: "3px",
      zIndex: 101,
      transition: "opacity .3s ease-in-out",
      backgroundColor: "inherit",
      opacity: 0,
      transitionDelay: "0s",
      whiteSpace: "nowrap",
    },
    ".cm-ySelectionCaret:hover > .cm-ySelectionInfo": {
      opacity: 1,
      transitionDelay: "0s",
    },
  },
  { dark: true },
);

/**
 * Syntax highlighting for markdown content.
 * Renders bold as bold, italic as italic, code as code, etc.
 */
export const markdownHighlighting = syntaxHighlighting(
  HighlightStyle.define([
    // Headings - styled via .cm-header-N classes above
    { tag: tags.heading1, class: "cm-header-1" },
    { tag: tags.heading2, class: "cm-header-2" },
    { tag: tags.heading3, class: "cm-header-3" },
    { tag: tags.heading4, class: "cm-header-4" },
    { tag: tags.heading5, class: "cm-header-5" },
    { tag: tags.heading6, class: "cm-header-6" },

    // Emphasis
    { tag: tags.emphasis, fontStyle: "italic", color: "#e2e8f0" },
    { tag: tags.strong, fontWeight: "bold", color: "#f1f5f9" },
    { tag: tags.strikethrough, textDecoration: "line-through", color: "#6b7280" },

    // Code
    {
      tag: tags.monospace,
      fontFamily: '"JetBrains Mono", monospace',
      backgroundColor: "#1e293b",
      color: "#7dd3fc", // sky-300
      borderRadius: "3px",
      padding: "1px 4px",
    },

    // Links
    { tag: tags.link, color: "#60a5fa", textDecoration: "underline" },
    { tag: tags.url, color: "#60a5fa" },

    // Lists
    { tag: tags.list, color: "#9ca3af" },

    // Quotes
    { tag: tags.quote, color: "#a1a1aa", fontStyle: "italic" },

    // Meta / markup characters (##, **, etc.)
    { tag: tags.processingInstruction, color: "#4b5563" },
    { tag: tags.meta, color: "#4b5563" },

    // Horizontal rule
    { tag: tags.contentSeparator, color: "#4b5563" },

    // HTML tags in markdown
    { tag: tags.angleBracket, color: "#4b5563" },
    { tag: tags.tagName, color: "#7dd3fc" },
    { tag: tags.attributeName, color: "#a78bfa" },
    { tag: tags.attributeValue, color: "#86efac" },
  ]),
);

import { useRef, useEffect, useState, useCallback } from "react";
import { EditorState } from "@codemirror/state";
import {
  EditorView,
  keymap,
  lineNumbers,
  highlightActiveLine,
  highlightActiveLineGutter,
  drawSelection,
  rectangularSelection,
  type ViewUpdate,
} from "@codemirror/view";
import { markdown, markdownLanguage } from "@codemirror/lang-markdown";
import { languages } from "@codemirror/language-data";
import { defaultKeymap, history, historyKeymap, indentWithTab } from "@codemirror/commands";
import {
  bracketMatching,
  indentOnInput,
  syntaxHighlighting,
  defaultHighlightStyle,
} from "@codemirror/language";
import { closeBrackets, closeBracketsKeymap } from "@codemirror/autocomplete";
import { searchKeymap, highlightSelectionMatches } from "@codemirror/search";
import { editorTheme, markdownHighlighting } from "./theme";
import { criticmarkDecorations } from "./criticmark-decorations";
import { suggestMode, setSuggestModeEffect } from "./suggest-mode";
import { suggestionActions } from "./suggestion-actions";
import { viewMode, viewModeEffect } from "./view-mode";
import {
  commentExtension,
  commentPopoverField,
  type CommentPopoverState,
} from "./comment-extension";
import ModeToolbar from "./ModeToolbar";
import SuggestionToolbar from "./SuggestionToolbar";
import CommentButton from "./CommentButton";
import CommentPopover from "./CommentPopover";
import DownloadButton from "./DownloadButton";
import type { EditorMode } from "./modes";
import { setAwarenessMode } from "./modes";
import UsernamePrompt from "./UsernamePrompt";
import UserPresence from "./UserPresence";
import {
  getStoredUsername,
  setStoredUsername,
  generateAnonName,
  setAwarenessUser,
} from "./user-awareness";

import * as Y from "yjs";
import { WebsocketProvider } from "y-websocket";
import { yCollab, yUndoManagerKeymap } from "y-codemirror.next";

interface EditorProps {
  initialContent?: string;
  docId?: string;
}

type ConnectionStatus = "connecting" | "connected" | "disconnected";

interface RemoteUser {
  name: string;
  color: string;
}

function getWsUrl(): string {
  const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
  return `${protocol}//${window.location.host}/ws`;
}

function ConnectionIndicator({ status }: { status: ConnectionStatus }) {
  const config: Record<ConnectionStatus, { color: string; label: string }> = {
    connecting: { color: "bg-yellow-400", label: "Connecting..." },
    connected: { color: "bg-green-400", label: "Connected" },
    disconnected: { color: "bg-red-400", label: "Offline" },
  };

  const { color, label } = config[status];

  return (
    <div className="flex items-center gap-1.5 text-xs text-gray-400 select-none">
      <span className={`inline-block w-2 h-2 rounded-full ${color}`} />
      {label}
    </div>
  );
}

export default function Editor({ initialContent = "", docId }: EditorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const providerRef = useRef<WebsocketProvider | null>(null);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>("connecting");
  const [mode, setMode] = useState<EditorMode>("edit");

  // Username state
  const [username, setUsername] = useState<string | null>(() => getStoredUsername());
  const [showUsernamePrompt, setShowUsernamePrompt] = useState(() => !getStoredUsername());
  const [remoteUsers, setRemoteUsers] = useState<RemoteUser[]>([]);
  const [commentPopover, setCommentPopover] = useState<CommentPopoverState>({
    open: false,
    comment: null,
    coords: null,
  });
  const editorWrapperRef = useRef<HTMLDivElement>(null);

  const collaborative = Boolean(docId);

  // Handle username submission (from prompt or edit)
  const handleUsernameSubmit = useCallback((name: string) => {
    setUsername(name);
    setStoredUsername(name);
    setShowUsernamePrompt(false);
    if (providerRef.current) {
      setAwarenessUser(providerRef.current.awareness, name);
    }
    // Update the CM6 suggest-mode field with the new username
    if (viewRef.current) {
      viewRef.current.dispatch({
        effects: setSuggestModeEffect.of({ username: name }),
      });
    }
  }, []);

  // Sync mode changes to Yjs awareness + CM6 suggest-mode state
  const handleModeChange = useCallback((newMode: EditorMode) => {
    setMode(newMode);
    if (providerRef.current) {
      setAwarenessMode(providerRef.current.awareness, newMode);
    }
    // Update the CM6 suggest-mode field
    if (viewRef.current) {
      viewRef.current.dispatch({
        effects: [
          setSuggestModeEffect.of({ mode: newMode }),
          viewModeEffect.of(newMode === "view"),
        ],
      });
    }
  }, []);

  useEffect(() => {
    if (!containerRef.current) return;
    // Don't create editor until we have a username
    if (!username) return;

    // Shared base extensions (no keymap yet -- added per mode below)
    const baseExtensions = [
      lineNumbers(),
      highlightActiveLine(),
      highlightActiveLineGutter(),
      drawSelection(),
      rectangularSelection(),
      indentOnInput(),
      bracketMatching(),
      closeBrackets(),
      highlightSelectionMatches(),
      markdown({
        base: markdownLanguage,
        codeLanguages: languages,
      }),
      editorTheme,
      markdownHighlighting,
      syntaxHighlighting(defaultHighlightStyle, { fallback: true }),
      criticmarkDecorations,
      suggestionActions,
      suggestMode(),
      viewMode(),
      commentExtension(),
      // Sync comment popover state from CM6 to React
      EditorView.updateListener.of((update: ViewUpdate) => {
        const popState = update.state.field(commentPopoverField, false);
        if (popState) {
          setCommentPopover((prev) => {
            // Only update if something changed
            if (prev.open !== popState.open || prev.comment?.start !== popState.comment?.start) {
              return popState;
            }
            return prev;
          });
        }
      }),
    ];

    let ydoc: Y.Doc | undefined;
    let provider: WebsocketProvider | undefined;

    if (collaborative && docId) {
      // -- Yjs collaborative mode --
      ydoc = new Y.Doc();

      // y-websocket builds URL as `${serverUrl}/${roomname}?${params}`.
      // Server matches paths starting with /ws and reads `doc` from query params.
      provider = new WebsocketProvider(getWsUrl(), docId, ydoc, {
        connect: true,
        params: { doc: docId },
      });
      providerRef.current = provider;

      // Set user info in awareness
      setAwarenessUser(provider.awareness, username);

      // Set initial mode in awareness
      setAwarenessMode(provider.awareness, mode);

      provider.on("status", ({ status }: { status: string }) => {
        if (status === "connected") {
          setConnectionStatus("connected");
        } else if (status === "connecting") {
          setConnectionStatus("connecting");
        } else {
          setConnectionStatus("disconnected");
        }
      });

      provider.on("connection-close", () => {
        setConnectionStatus("disconnected");
      });

      // Track remote users via awareness
      const updateRemoteUsers = () => {
        if (!provider) return;
        const states = provider.awareness.getStates();
        const localClientId = provider.awareness.clientID;
        const users: RemoteUser[] = [];
        states.forEach((state, clientId) => {
          if (clientId === localClientId) return;
          if (state.user?.name) {
            users.push({
              name: state.user.name,
              color: state.user.color || "#60a5fa",
            });
          }
        });
        setRemoteUsers(users);
      };

      provider.awareness.on("change", updateRemoteUsers);
      // Initial population
      updateRemoteUsers();

      const ytext = ydoc.getText("codemirror");

      const state = EditorState.create({
        extensions: [
          ...baseExtensions,
          yCollab(ytext, provider.awareness),
          keymap.of([
            ...defaultKeymap,
            ...yUndoManagerKeymap,
            ...closeBracketsKeymap,
            ...searchKeymap,
            indentWithTab,
          ]),
        ],
      });

      const view = new EditorView({
        state,
        parent: containerRef.current,
      });

      viewRef.current = view;

      // Set initial mode state (suggest-mode + view-mode + username)
      view.dispatch({
        effects: [setSuggestModeEffect.of({ mode, username }), viewModeEffect.of(mode === "view")],
      });
    } else {
      // -- Local-only fallback (no docId) --
      setConnectionStatus("disconnected");

      const state = EditorState.create({
        doc: initialContent,
        extensions: [
          ...baseExtensions,
          history(),
          keymap.of([
            ...defaultKeymap,
            ...historyKeymap,
            ...closeBracketsKeymap,
            ...searchKeymap,
            indentWithTab,
          ]),
        ],
      });

      const view = new EditorView({
        state,
        parent: containerRef.current,
      });

      viewRef.current = view;

      // Set initial mode state (suggest-mode + view-mode + username)
      view.dispatch({
        effects: [setSuggestModeEffect.of({ mode, username }), viewModeEffect.of(mode === "view")],
      });
    }

    return () => {
      if (viewRef.current) {
        viewRef.current.destroy();
        viewRef.current = null;
      }

      if (provider) {
        provider.disconnect();
        provider.destroy();
      }
      providerRef.current = null;

      if (ydoc) {
        ydoc.destroy();
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- editor is intentionally only recreated when docId/username change
  }, [docId, username]);

  return (
    <div className="relative flex-1 min-h-0 flex flex-col overflow-hidden">
      {/* Username prompt modal */}
      {showUsernamePrompt && (
        <UsernamePrompt
          defaultValue={username || generateAnonName()}
          onSubmit={handleUsernameSubmit}
        />
      )}

      {/* Editor toolbar */}
      <div className="flex items-center justify-between px-4 py-1.5 border-b border-gray-800 bg-gray-950">
        <div className="flex items-center gap-3">
          <ModeToolbar mode={mode} onModeChange={handleModeChange} />
          <SuggestionToolbar viewRef={viewRef} />
          <CommentButton viewRef={viewRef} />
          <DownloadButton viewRef={viewRef} docId={docId} />
        </div>
        <div className="flex items-center gap-3">
          {collaborative && username && (
            <UserPresence
              username={username}
              remoteUsers={remoteUsers}
              onEditUsername={() => setShowUsernamePrompt(true)}
            />
          )}
          {collaborative && <ConnectionIndicator status={connectionStatus} />}
        </div>
      </div>

      {/* Editor area with comment popover */}
      <div ref={editorWrapperRef} className="relative flex-1 min-h-0 overflow-hidden">
        <div ref={containerRef} className="h-full overflow-hidden" />
        <CommentPopover
          state={commentPopover}
          viewRef={viewRef}
          username={username || "anonymous"}
          editorContainerRef={editorWrapperRef}
        />
      </div>
    </div>
  );
}

