1	/**
2	 * CodeMirror 6 extension for View mode.
3	 *
4	 * When active, makes the editor read-only with a clean reading experience:
5	 *   - Editor is set to readOnly
6	 *   - Cursor is hidden
7	 *   - Active line highlighting is suppressed
8	 *   - No editing affordances shown
9	 *
10	 * CriticMark decorations remain visible and interactive (for M4 features).
11	 */
12	
13	import { StateField, StateEffect, type Extension, Compartment } from "@codemirror/state";
14	import { EditorView } from "@codemirror/view";
15	
16	/** Effect to toggle view mode on/off. */
17	export const viewModeEffect = StateEffect.define<boolean>();
18	
19	/** StateField tracking whether view mode is active. */
20	export const viewModeField = StateField.define<boolean>({
21	  create() {
22	    return false;
23	  },
24	  update(value, tr) {
25	    for (const effect of tr.effects) {
26	      if (effect.is(viewModeEffect)) {
27	        return effect.value;
28	      }
29	    }
30	    return value;
31	  },
32	});
33	
34	/**
35	 * Theme overrides applied when view mode is active.
36	 * Hides cursor and removes editing visual cues.
37	 */
38	const viewModeTheme = EditorView.theme({
39	  "&.cm-view-mode .cm-cursor, &.cm-view-mode .cm-dropCursor": {
40	    display: "none !important",
41	  },
42	  "&.cm-view-mode .cm-activeLine": {
43	    backgroundColor: "transparent",
44	  },
45	  "&.cm-view-mode .cm-activeLineGutter": {
46	    backgroundColor: "transparent",
47	    color: "#4b5563",
48	  },
49	  // Slightly widen content area for comfortable reading
50	  "&.cm-view-mode .cm-content": {
51	    caretColor: "transparent",
52	  },
53	});
54	
55	/** Compartment for dynamically toggling readOnly. */
56	const readOnlyCompartment = new Compartment();
57	
58	/**
59	 * ViewPlugin that syncs the viewModeField to the editor DOM class
60	 * and reconfigures readOnly dynamically.
61	 */
62	const viewModeUpdater = EditorView.updateListener.of((update) => {
63	  const isViewMode = update.state.field(viewModeField);
64	  const wasViewMode = update.startState.field(viewModeField, false) ?? false;
65	
66	  // Toggle the CSS class on the editor root
67	  if (isViewMode !== wasViewMode) {
68	    if (isViewMode) {
69	      update.view.dom.classList.add("cm-view-mode");
70	    } else {
71	      update.view.dom.classList.remove("cm-view-mode");
72	    }
73	
74	    // Reconfigure readOnly
75	    update.view.dispatch({
76	      effects: readOnlyCompartment.reconfigure(isViewMode ? EditorView.editable.of(false) : []),
77	    });
78	  }
79	});
80	
81	/**
82	 * Returns the view mode extension bundle.
83	 * Add this to your editor's extensions array.
84	 */
85	export function viewMode(): Extension {
86	  return [viewModeField, viewModeTheme, viewModeUpdater, readOnlyCompartment.of([])];
87	}
