1	/**
2	 * CodeMirror 6 extension for accept/reject UI on CriticMark suggestions.
3	 *
4	 * Adds small inline widget buttons (checkmark/X) after each CriticMark
5	 * addition, deletion, or substitution annotation. Clicking accept or reject
6	 * resolves the suggestion by transforming the document text.
7	 *
8	 * Accept/reject semantics:
9	 *   Accept addition  {++text++}      -> text
10	 *   Reject addition  {++text++}      -> (removed)
11	 *   Accept deletion  {--text--}      -> (removed)
12	 *   Reject deletion  {--text--}      -> text
13	 *   Accept substitution {~~old~>new~~} -> new
14	 *   Reject substitution {~~old~>new~~} -> old
15	 */
16	
17	import {
18	  ViewPlugin,
19	  Decoration,
20	  WidgetType,
21	  type DecorationSet,
22	  type EditorView,
23	  type ViewUpdate,
24	} from "@codemirror/view";
25	import { RangeSetBuilder } from "@codemirror/state";
26	
27	// ---------------------------------------------------------------------------
28	// Regex for CriticMark suggestions (additions, deletions, substitutions only)
29	// ---------------------------------------------------------------------------
30	
31	const SUGGESTION_RE = /\{\+\+([\s\S]*?)\+\+\}|\{--([\s\S]*?)--\}|\{~~([\s\S]*?)~>([\s\S]*?)~~\}/g;
32	
33	// ---------------------------------------------------------------------------
34	// Parse author prefix from content (e.g. "@user: actual text" -> "actual text")
35	// ---------------------------------------------------------------------------
36	
37	function stripAuthorPrefix(raw: string): string {
38	  const m = raw.match(/^@[^:]+:\s*([\s\S]*)$/);
39	  return m ? m[1] : raw;
40	}
41	
42	// ---------------------------------------------------------------------------
43	// Types for suggestion info attached to widgets
44	// ---------------------------------------------------------------------------
45	
46	interface SuggestionInfo {
47	  type: "addition" | "deletion" | "substitution";
48	  /** Absolute start of the entire CriticMark annotation in the doc */
49	  from: number;
50	  /** Absolute end of the entire CriticMark annotation in the doc */
51	  to: number;
52	  /** Text to insert when accepted */
53	  acceptText: string;
54	  /** Text to insert when rejected */
55	  rejectText: string;
56	}
57	
58	// ---------------------------------------------------------------------------
59	// Widget: accept/reject button pair
60	// ---------------------------------------------------------------------------
61	
62	class SuggestionActionWidget extends WidgetType {
63	  constructor(readonly info: SuggestionInfo) {
64	    super();
65	  }
66	
67	  eq(other: SuggestionActionWidget): boolean {
68	    return (
69	      this.info.from === other.info.from &&
70	      this.info.to === other.info.to &&
71	      this.info.type === other.info.type
72	    );
73	  }
74	
75	  toDOM(view: EditorView): HTMLElement {
76	    const container = document.createElement("span");
77	    container.className = "cm-suggestion-actions";
78	    container.setAttribute("aria-label", "Suggestion actions");
79	
80	    const acceptBtn = document.createElement("button");
81	    acceptBtn.className = "cm-suggestion-accept";
82	    acceptBtn.textContent = "\u2713"; // checkmark
83	    acceptBtn.title = "Accept suggestion";
84	    acceptBtn.setAttribute("aria-label", "Accept suggestion");
85	    acceptBtn.addEventListener("mousedown", (e) => {
86	      e.preventDefault();
87	      e.stopPropagation();
88	      resolveSuggestion(view, this.info, "accept");
89	    });
90	
91	    const rejectBtn = document.createElement("button");
92	    rejectBtn.className = "cm-suggestion-reject";
93	    rejectBtn.textContent = "\u2717"; // X mark
94	    rejectBtn.title = "Reject suggestion";
95	    rejectBtn.setAttribute("aria-label", "Reject suggestion");
96	    rejectBtn.addEventListener("mousedown", (e) => {
97	      e.preventDefault();
98	      e.stopPropagation();
99	      resolveSuggestion(view, this.info, "reject");
100	    });
101	
102	    container.appendChild(acceptBtn);
103	    container.appendChild(rejectBtn);
104	    return container;
105	  }
106	
107	  ignoreEvent(): boolean {
108	    return false;
109	  }
110	}
111	
112	// ---------------------------------------------------------------------------
113	// Resolve a single suggestion
114	// ---------------------------------------------------------------------------
115	
116	function resolveSuggestion(
117	  view: EditorView,
118	  info: SuggestionInfo,
119	  action: "accept" | "reject",
120	): void {
121	  const replacement = action === "accept" ? info.acceptText : info.rejectText;
122	  view.dispatch({
123	    changes: { from: info.from, to: info.to, insert: replacement },
124	  });
125	}
126	
127	// ---------------------------------------------------------------------------
128	// Build decorations: scan for suggestions, add widget after each
129	// ---------------------------------------------------------------------------
130	
131	function buildSuggestionDecorations(view: EditorView): DecorationSet {
132	  const builder = new RangeSetBuilder<Decoration>();
133	  const doc = view.state.doc;
134	
135	  for (const { from, to } of view.visibleRanges) {
136	    const lineFrom = doc.lineAt(from).from;
137	    const lineTo = doc.lineAt(to).to;
138	    const text = doc.sliceString(lineFrom, lineTo);
139	
140	    SUGGESTION_RE.lastIndex = 0;
141	    let match: RegExpExecArray | null;
142	
143	    while ((match = SUGGESTION_RE.exec(text)) !== null) {
144	      const absStart = lineFrom + match.index;
145	      const absEnd = absStart + match[0].length;
146	
147	      let info: SuggestionInfo;
148	
149	      if (match[1] !== undefined) {
150	        // Addition: {++content++}
151	        const content = stripAuthorPrefix(match[1]);
152	        info = {
153	          type: "addition",
154	          from: absStart,
155	          to: absEnd,
156	          acceptText: content,
157	          rejectText: "",
158	        };
159	      } else if (match[2] !== undefined) {
160	        // Deletion: {--content--}
161	        const content = stripAuthorPrefix(match[2]);
162	        info = {
163	          type: "deletion",
164	          from: absStart,
165	          to: absEnd,
166	          acceptText: "",
167	          rejectText: content,
168	        };
169	      } else if (match[3] !== undefined && match[4] !== undefined) {
170	        // Substitution: {~~old~>new~~}
171	        info = {
172	          type: "substitution",
173	          from: absStart,
174	          to: absEnd,
175	          acceptText: match[4],
176	          rejectText: match[3],
177	        };
178	      } else {
179	        continue;
180	      }
181	
182	      // Place widget decoration at the end of the annotation
183	      builder.add(
184	        absEnd,
185	        absEnd,
186	        Decoration.widget({
187	          widget: new SuggestionActionWidget(info),
188	          side: 1,
189	        }),
190	      );
191	    }
192	  }
193	
194	  return builder.finish();
195	}
196	
197	// ---------------------------------------------------------------------------
198	// ViewPlugin
199	// ---------------------------------------------------------------------------
200	
201	export const suggestionActions = ViewPlugin.fromClass(
202	  class {
203	    decorations: DecorationSet;
204	
205	    constructor(view: EditorView) {
206	      this.decorations = buildSuggestionDecorations(view);
207	    }
208	
209	    update(update: ViewUpdate) {
210	      if (update.docChanged || update.viewportChanged) {
211	        this.decorations = buildSuggestionDecorations(update.view);
212	      }
213	    }
214	  },
215	  {
216	    decorations: (v) => v.decorations,
217	  },
218	);
219	
220	// ---------------------------------------------------------------------------
221	// Bulk operations: accept all / reject all
222	// ---------------------------------------------------------------------------
223	
224	/**
225	 * Find all CriticMark suggestions in the full document and resolve them.
226	 * Must process from end to start to avoid offset shifting.
227	 */
228	export function resolveAllSuggestions(view: EditorView, action: "accept" | "reject"): void {
229	  const doc = view.state.doc;
230	  const text = doc.toString();
231	
232	  SUGGESTION_RE.lastIndex = 0;
233	  const suggestions: SuggestionInfo[] = [];
234	  let match: RegExpExecArray | null;
235	
236	  while ((match = SUGGESTION_RE.exec(text)) !== null) {
237	    const from = match.index;
238	    const to = from + match[0].length;
239	
240	    if (match[1] !== undefined) {
241	      const content = stripAuthorPrefix(match[1]);
242	      suggestions.push({
243	        type: "addition",
244	        from,
245	        to,
246	        acceptText: content,
247	        rejectText: "",
248	      });
249	    } else if (match[2] !== undefined) {
250	      const content = stripAuthorPrefix(match[2]);
251	      suggestions.push({
252	        type: "deletion",
253	        from,
254	        to,
255	        acceptText: "",
256	        rejectText: content,
257	      });
258	    } else if (match[3] !== undefined && match[4] !== undefined) {
259	      suggestions.push({
260	        type: "substitution",
261	        from,
262	        to,
263	        acceptText: match[4],
264	        rejectText: match[3],
265	      });
266	    }
267	  }
268	
269	  if (suggestions.length === 0) return;
270	
271	  // Build changes from end to start so offsets don't shift
272	  const changes = suggestions
273	    .sort((a, b) => b.from - a.from)
274	    .map((s) => ({
275	      from: s.from,
276	      to: s.to,
277	      insert: action === "accept" ? s.acceptText : s.rejectText,
278	    }));
279	
280	  view.dispatch({ changes });
281	}
282

