1	/**
2	 * Comment popover: displays when a user clicks on a CriticMark comment range.
3	 *
4	 * Shows:
5	 *   - Parsed thread entries (author, timestamp, message)
6	 *   - Raw body as fallback if no threads are parsed
7	 *   - Input field to add a new reply
8	 *   - Dismiss button (X)
9	 *
10	 * Positioned absolutely near the comment text in the editor.
11	 */
12	
13	import { useState, useRef, useEffect, useCallback } from "react";
14	import type { EditorView } from "@codemirror/view";
15	import type { CommentPopoverState } from "./comment-extension";
16	import { appendCommentEntry, closeCommentPopover, resolveComment } from "./comment-extension";
17	
18	interface CommentPopoverProps {
19	  state: CommentPopoverState;
20	  viewRef: React.RefObject<EditorView | null>;
21	  username: string;
22	  editorContainerRef: React.RefObject<HTMLDivElement | null>;
23	}
24	
25	function formatTimestamp(ts: string): string {
26	  try {
27	    const d = new Date(ts);
28	    if (isNaN(d.getTime())) return ts;
29	    return d.toLocaleString(undefined, {
30	      month: "short",
31	      day: "numeric",
32	      hour: "2-digit",
33	      minute: "2-digit",
34	    });
35	  } catch {
36	    return ts;
37	  }
38	}
39	
40	export default function CommentPopover({
41	  state,
42	  viewRef,
43	  username,
44	  editorContainerRef,
45	}: CommentPopoverProps) {
46	  // Reset reply text when a different comment opens by using the comment start
47	  // position as a key for the state. This avoids calling setState in an effect.
48	  const commentKey = state.open ? (state.comment?.start ?? 0) : -1;
49	  const [replyState, setReplyState] = useState({ key: commentKey, text: "" });
50	  if (replyState.key !== commentKey) {
51	    setReplyState({ key: commentKey, text: "" });
52	  }
53	  const replyText = replyState.text;
54	  const setReplyText = (text: string) => setReplyState({ key: commentKey, text });
55	
56	  const inputRef = useRef<HTMLInputElement>(null);
57	  const popoverRef = useRef<HTMLDivElement>(null);
58	
59	  // Focus input when popover opens
60	  useEffect(() => {
61	    if (state.open) {
62	      // Small delay to allow render
63	      setTimeout(() => inputRef.current?.focus(), 50);
64	    }
65	  }, [state.open, state.comment?.start]);
66	
67	  // Click outside to dismiss
68	  useEffect(() => {
69	    if (!state.open) return;
70	
71	    const handleClickOutside = (e: MouseEvent) => {
72	      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
73	        if (viewRef.current) {
74	          closeCommentPopover(viewRef.current);
75	        }
76	      }
77	    };
78	
79	    // Delay adding the listener so the opening click doesn't immediately close
80	    const timer = setTimeout(() => {
81	      document.addEventListener("mousedown", handleClickOutside);
82	    }, 100);
83	
84	    return () => {
85	      clearTimeout(timer);
86	      document.removeEventListener("mousedown", handleClickOutside);
87	    };
88	  }, [state.open, viewRef]);
89	
90	  const handleSubmit = useCallback(() => {
91	    if (!replyText.trim() || !viewRef.current || !state.comment) return;
92	    appendCommentEntry(viewRef.current, state.comment, username, replyText.trim());
93	    setReplyState((prev) => ({ ...prev, text: "" }));
94	  }, [replyText, viewRef, state.comment, username]);
95	
96	  const handleResolve = useCallback(() => {
97	    if (!viewRef.current || !state.comment) return;
98	    resolveComment(viewRef.current, state.comment);
99	  }, [viewRef, state.comment]);
100	
101	  if (!state.open || !state.comment || !state.coords) return null;
102	
103	  const { comment, coords } = state;
104	
105	  // Compute position relative to the editor container.
106	  // Safe to read the ref here: this code only runs when the popover is visible,
107	  // and the container ref is stable (it doesn't drive re-renders).
108	  // eslint-disable-next-line react-hooks/refs
109	  const containerRect = editorContainerRef.current?.getBoundingClientRect();
110	  const left = containerRect ? coords.x - containerRect.left : coords.x;
111	  const top = containerRect ? coords.y - containerRect.top : coords.y;
112	
113	  const hasThreads = comment.threads.length > 0;
114	
115	  return (
116	    <div
117	      ref={popoverRef}
118	      className="absolute z-50 w-80 bg-gray-900 border border-gray-700 rounded-lg shadow-xl"
119	      style={{
120	        left: `${Math.max(8, Math.min(left, (containerRect?.width ?? 600) - 330))}px`,
121	        top: `${top}px`,
122	      }}
123	    >
124	      {/* Header */}
125	      <div className="flex items-center justify-between px-3 py-2 border-b border-gray-800">
126	        <span className="text-xs font-medium text-gray-300">Comment</span>
127	        <div className="flex items-center gap-1">
128	          <button
129	            onClick={handleResolve}
130	            className="px-1.5 py-0.5 text-[10px] font-medium rounded transition-colors
131	              text-green-400 hover:text-green-300 hover:bg-green-900/30
132	              border border-green-800/50 hover:border-green-700/50"
133	            title="Resolve comment (removes annotation)"
134	          >
135	            Resolve
136	          </button>
137	          <button
138	            onClick={() => {
139	              if (viewRef.current) closeCommentPopover(viewRef.current);
140	            }}
141	            className="text-gray-500 hover:text-gray-300 text-sm leading-none px-1"
142	            title="Close"
143	          >
144	            &#x2715;
145	          </button>
146	        </div>
147	      </div>
148	
149	      {/* Thread entries */}
150	      <div className="max-h-60 overflow-y-auto">
151	        {hasThreads ? (
152	          comment.threads.map((thread, i) => (
153	            <div key={i} className="px-3 py-2 border-b border-gray-800/50 last:border-0">
154	              <div className="flex items-baseline gap-2 mb-0.5">
155	                <span className="text-xs font-semibold text-blue-400">@{thread.user}</span>
156	                <span className="text-[10px] text-gray-500">
157	                  {formatTimestamp(thread.timestamp)}
158	                </span>
159	              </div>
160	              <p className="text-sm text-gray-200 whitespace-pre-wrap leading-relaxed">
161	                {thread.message}
162	              </p>
163	            </div>
164	          ))
165	        ) : (
166	          <div className="px-3 py-2">
167	            <p className="text-sm text-gray-300 whitespace-pre-wrap leading-relaxed">
168	              {comment.body || "(empty comment)"}
169	            </p>
170	          </div>
171	        )}
172	      </div>
173	
174	      {/* Reply input */}
175	      <div className="px-3 py-2 border-t border-gray-800">
176	        <form
177	          onSubmit={(e) => {
178	            e.preventDefault();
179	            handleSubmit();
180	          }}
181	          className="flex items-center gap-2"
182	        >
183	          <input
184	            ref={inputRef}
185	            type="text"
186	            value={replyText}
187	            onChange={(e) => setReplyText(e.target.value)}
188	            placeholder="Reply..."
189	            className="flex-1 bg-gray-800 text-sm text-gray-200 px-2 py-1.5
190	              rounded border border-gray-700 focus:border-blue-500
191	              focus:outline-none placeholder-gray-500
192	              font-mono"
193	            onKeyDown={(e) => {
194	              // Prevent CM6 from capturing keys while typing in the input
195	              e.stopPropagation();
196	              if (e.key === "Escape") {
197	                if (viewRef.current) closeCommentPopover(viewRef.current);
198	              }
199	            }}
200	          />
201	          <button
202	            type="submit"
203	            disabled={!replyText.trim()}
204	            className="px-2 py-1.5 text-xs font-medium rounded transition-colors
205	              text-yellow-400 hover:text-yellow-300 hover:bg-yellow-900/30
206	              border border-yellow-800/50 hover:border-yellow-700/50
207	              disabled:opacity-30 disabled:cursor-not-allowed"
208	          >
209	            Reply
210	          </button>
211	        </form>
212	      </div>
213	    </div>
214	  );
215	}
