cat <<'SCRIPT' > /tmp/test-selection.js
const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  // Navigate to a local-only editor (no docId needed)
  await page.goto('http://localhost:5173/test-selection');

  // Wait for the username prompt and submit a name
  await page.waitForSelector('input[placeholder]', { timeout: 5000 });
  const input = await page.$('input[placeholder]');
  await input.fill('TestUser');
  // Submit - look for the button
  const submitBtn = await page.$('button[type="submit"]');
  if (submitBtn) await submitBtn.click();

  // Wait for editor to appear
  await page.waitForSelector('.cm-content', { timeout: 5000 });

  // Type some text
  await page.click('.cm-content');
  await page.keyboard.type('Hello World this is a test of text selection');

  // Wait a moment for the text to be committed
  await page.waitForTimeout(500);

  // Get the text content to verify it was typed
  const textContent = await page.$eval('.cm-content', el => el.textContent);
  console.log('Editor content:', JSON.stringify(textContent));

  // Now try to select text using keyboard (Ctrl+A)
  await page.keyboard.press('Control+a');
  await page.waitForTimeout(200);

  // Check if selection exists in CodeMirror state
  const selectionInfo = await page.evaluate(() => {
    // Access CodeMirror view from the DOM
    const cmContent = document.querySelector('.cm-content');
    const cmEditor = cmContent?.closest('.cm-editor');
    if (!cmEditor) return { error: 'no cm-editor found' };

    // Check for selection background elements
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    const selLayer = document.querySelector('.cm-selectionLayer');

    // Check computed styles on cm-content
    const contentStyle = window.getComputedStyle(cmContent);
    const userSelect = contentStyle.userSelect || contentStyle.webkitUserSelect;

    // Check if native selection exists
    const nativeSel = window.getSelection();

    return {
      selectionBackgrounds: selBg.length,
      selectionLayerExists: !!selLayer,
      selectionLayerDisplay: selLayer ? window.getComputedStyle(selLayer).display : 'N/A',
      selectionLayerZIndex: selLayer ? window.getComputedStyle(selLayer).zIndex : 'N/A',
      contentUserSelect: userSelect,
      nativeSelectionType: nativeSel?.type,
      nativeSelectionText: nativeSel?.toString()?.substring(0, 50),
      cmLineCount: document.querySelectorAll('.cm-line').length,
      activeLineHasBg: (() => {
        const activeLine = document.querySelector('.cm-activeLine');
        if (!activeLine) return 'no active line';
        return window.getComputedStyle(activeLine).backgroundColor;
      })(),
    };
  });

  console.log('Selection info:', JSON.stringify(selectionInfo, null, 2));

  // Now try mouse-based selection
  await page.keyboard.press('Home');
  await page.waitForTimeout(100);

  // Click at beginning of text, then shift+click at end
  const contentBox = await page.$('.cm-content');
  const box = await contentBox.boundingBox();

  // Click at start
  await page.mouse.click(box.x + 10, box.y + 20);
  await page.waitForTimeout(100);

  // Shift+click further right to select
  await page.mouse.click(box.x + 200, box.y + 20, { modifiers: ['Shift'] });
  await page.waitForTimeout(200);

  const mouseSelInfo = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    return {
      selectionBackgrounds: selBg.length,
      selBgDimensions: Array.from(selBg).map(el => {
        const rect = el.getBoundingClientRect();
        return { width: rect.width, height: rect.height };
      }),
    };
  });

  console.log('Mouse selection info:', JSON.stringify(mouseSelInfo, null, 2));

  // Try click-and-drag selection
  await page.mouse.click(box.x + 10, box.y + 20);
  await page.waitForTimeout(50);
  await page.mouse.move(box.x + 10, box.y + 20);
  await page.mouse.down();
  // Slowly drag to the right
  for (let i = 0; i < 10; i++) {
    await page.mouse.move(box.x + 10 + (i * 20), box.y + 20);
    await page.waitForTimeout(30);
  }
  await page.waitForTimeout(100);

  const dragSelInfo = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    const nativeSel = window.getSelection();
    return {
      selectionBackgrounds: selBg.length,
      nativeSelectionType: nativeSel?.type,
      nativeSelectionLength: nativeSel?.toString()?.length || 0,
    };
  });

  console.log('Drag selection info:', JSON.stringify(dragSelInfo, null, 2));

  await page.mouse.up();

  await browser.close();
  console.log('Test complete');
})().catch(err => {
  console.error('Test failed:', err.message);
  process.exit(1);
});
