const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  // Navigate to the editor with a docId
  await page.goto('http://localhost:5173/test-selection-doc');

  // Wait for the username prompt
  await page.waitForSelector('input[placeholder="Your name"]', { timeout: 10000 });
  const input = await page.$('input[placeholder="Your name"]');
  await input.fill('TestUser');
  await page.click('button:has-text("Join")');

  // Wait for editor to appear
  await page.waitForSelector('.cm-content', { timeout: 10000 });
  await page.waitForTimeout(1000); // wait for yjs connection

  // Click on editor to focus
  await page.click('.cm-content');
  await page.waitForTimeout(200);

  // Type some text
  await page.keyboard.type('Hello World this is a test of text selection in CodeMirror');
  await page.waitForTimeout(500);

  // Get content
  const textContent = await page.$eval('.cm-content', el => el.textContent);
  console.log('=== Editor content ===');
  console.log(textContent.substring(0, 100));

  // Test 1: Keyboard selection (Ctrl+A)
  console.log('\n=== Test 1: Ctrl+A selection ===');
  await page.keyboard.press('Control+a');
  await page.waitForTimeout(300);

  const test1 = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    const selLayer = document.querySelector('.cm-selectionLayer');
    return {
      selectionBackgroundCount: selBg.length,
      selectionLayerExists: !!selLayer,
      selBgVisible: Array.from(selBg).map(el => {
        const style = window.getComputedStyle(el);
        const rect = el.getBoundingClientRect();
        return {
          width: Math.round(rect.width),
          height: Math.round(rect.height),
          bg: style.backgroundColor,
          display: style.display,
          visibility: style.visibility,
          opacity: style.opacity,
        };
      }),
    };
  });
  console.log(JSON.stringify(test1, null, 2));

  // Test 2: Click to deselect, then shift+click to select
  console.log('\n=== Test 2: Click + Shift+Click selection ===');
  const contentEl = await page.$('.cm-content');
  const box = await contentEl.boundingBox();

  await page.mouse.click(box.x + 10, box.y + 10);
  await page.waitForTimeout(200);
  await page.mouse.click(box.x + 200, box.y + 10, { modifiers: ['Shift'] });
  await page.waitForTimeout(300);

  const test2 = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    return {
      selectionBackgroundCount: selBg.length,
      selBgRects: Array.from(selBg).map(el => {
        const rect = el.getBoundingClientRect();
        return { width: Math.round(rect.width), height: Math.round(rect.height) };
      }),
    };
  });
  console.log(JSON.stringify(test2, null, 2));

  // Test 3: Click and drag selection
  console.log('\n=== Test 3: Click and Drag selection ===');
  await page.mouse.click(box.x + 10, box.y + 10);
  await page.waitForTimeout(100);

  await page.mouse.move(box.x + 10, box.y + 10);
  await page.mouse.down();

  // Drag slowly to the right
  for (let i = 1; i <= 15; i++) {
    await page.mouse.move(box.x + 10 + (i * 15), box.y + 10);
    await page.waitForTimeout(20);
  }
  await page.waitForTimeout(200);

  const test3 = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    const nativeSel = window.getSelection();
    return {
      selectionBackgroundCount: selBg.length,
      nativeSelectionType: nativeSel?.type,
      nativeSelectionText: nativeSel?.toString()?.substring(0, 50),
      selBgRects: Array.from(selBg).map(el => {
        const rect = el.getBoundingClientRect();
        return { width: Math.round(rect.width), height: Math.round(rect.height) };
      }),
    };
  });
  console.log(JSON.stringify(test3, null, 2));

  await page.mouse.up();

  // Test 4: Check for any drag-related events/behaviors
  console.log('\n=== Test 4: Check drag behavior ===');

  // First select some text
  await page.keyboard.press('Control+a');
  await page.waitForTimeout(200);

  // Then try clicking on selected text and dragging (this would trigger drag-and-drop)
  await page.mouse.click(box.x + 50, box.y + 10);
  await page.waitForTimeout(200);

  // Double-click to select a word
  await page.mouse.dblclick(box.x + 50, box.y + 10);
  await page.waitForTimeout(200);

  const test4pre = await page.evaluate(() => {
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    return { selBgAfterDblClick: selBg.length };
  });
  console.log('After double-click:', JSON.stringify(test4pre));

  // Now try to drag the selected word
  await page.mouse.move(box.x + 50, box.y + 10);
  await page.mouse.down();
  for (let i = 1; i <= 10; i++) {
    await page.mouse.move(box.x + 50 + (i * 20), box.y + 10);
    await page.waitForTimeout(30);
  }
  await page.waitForTimeout(200);

  const test4 = await page.evaluate(() => {
    const content = document.querySelector('.cm-content')?.textContent;
    const selBg = document.querySelectorAll('.cm-selectionBackground');
    return {
      contentAfterDrag: content?.substring(0, 100),
      selBgCount: selBg.length,
    };
  });
  console.log('After drag:', JSON.stringify(test4));

  await page.mouse.up();

  // Test 5: Check CSS properties
  console.log('\n=== Test 5: CSS inspection ===');
  const cssInfo = await page.evaluate(() => {
    const content = document.querySelector('.cm-content');
    const line = document.querySelector('.cm-line');
    const editor = document.querySelector('.cm-editor');
    const scroller = document.querySelector('.cm-scroller');
    const selLayer = document.querySelector('.cm-selectionLayer');

    const getStyles = (el, name) => {
      if (!el) return 'N/A';
      const s = window.getComputedStyle(el);
      return {
        userSelect: s.userSelect,
        pointerEvents: s.pointerEvents,
        position: s.position,
        zIndex: s.zIndex,
        backgroundColor: s.backgroundColor,
        caretColor: s.caretColor,
      };
    };

    return {
      cmContent: getStyles(content, '.cm-content'),
      cmLine: getStyles(line, '.cm-line'),
      cmEditor: getStyles(editor, '.cm-editor'),
      cmScroller: getStyles(scroller, '.cm-scroller'),
      cmSelectionLayer: getStyles(selLayer, '.cm-selectionLayer'),
      contentEditable: content?.getAttribute('contenteditable'),
      lineEditable: line?.getAttribute('contenteditable'),
    };
  });
  console.log(JSON.stringify(cssInfo, null, 2));

  await browser.close();
  console.log('\n=== Test complete ===');
})().catch(err => {
  console.error('Test failed:', err.message);
  process.exit(1);
});

