import { EditorView } from "@codemirror/view";
import { HighlightStyle, syntaxHighlighting } from "@codemirror/language";
import { tags } from "@lezer/highlight";

/**
 * Dark editor theme matching the app's Tailwind design.
 * Uses gray-950 background, gray-100 text, JetBrains Mono font.
 */
export const editorTheme = EditorView.theme(
  {
    "&": {
      color: "#f3f4f6", // gray-100
      backgroundColor: "#030712", // gray-950
      fontFamily: '"JetBrains Mono", ui-monospace, SFMono-Regular, monospace',
      fontSize: "15px",
      height: "100%",
    },
    "&.cm-focused": {
      outline: "none",
    },
    ".cm-content": {
      caretColor: "#60a5fa", // blue-400
      padding: "1rem 0",
      lineHeight: "1.7",
    },
    ".cm-cursor, .cm-dropCursor": {
      borderLeftColor: "#60a5fa",
      borderLeftWidth: "2px",
    },
    ".cm-selectionBackground, &.cm-focused .cm-selectionBackground": {
      backgroundColor: "#1e3a5f",
    },
    ".cm-activeLine": {
      backgroundColor: "#0d1117",
    },
    ".cm-gutters": {
      backgroundColor: "#030712",
      color: "#4b5563", // gray-600
      border: "none",
      paddingRight: "8px",
    },
    ".cm-activeLineGutter": {
      backgroundColor: "#0d1117",
      color: "#9ca3af", // gray-400
    },
    ".cm-scroller": {
      overflow: "auto",
    },
    // Inline markdown rendering styles
    ".cm-header-1": {
      fontSize: "2em",
      fontWeight: "700",
      lineHeight: "1.3",
      color: "#f9fafb",
    },
    ".cm-header-2": {
      fontSize: "1.5em",
      fontWeight: "600",
      lineHeight: "1.4",
      color: "#f3f4f6",
    },
    ".cm-header-3": {
      fontSize: "1.25em",
      fontWeight: "600",
      lineHeight: "1.5",
      color: "#e5e7eb",
    },
    ".cm-header-4": {
      fontSize: "1.1em",
      fontWeight: "600",
      color: "#d1d5db",
    },
    ".cm-header-5": {
      fontSize: "1.05em",
      fontWeight: "600",
      color: "#d1d5db",
    },
    ".cm-header-6": {
      fontSize: "1em",
      fontWeight: "600",
      color: "#9ca3af",
    },

    // CriticMark decoration styles
    ".cm-criticmark-addition": {
      backgroundColor: "rgba(34, 197, 94, 0.15)", // green-500/15
      color: "#86efac", // green-300
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-deletion": {
      backgroundColor: "rgba(239, 68, 68, 0.15)", // red-500/15
      color: "#fca5a5", // red-300
      textDecoration: "line-through",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-substitution-old": {
      backgroundColor: "rgba(239, 68, 68, 0.15)",
      color: "#fca5a5",
      textDecoration: "line-through",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-substitution-new": {
      backgroundColor: "rgba(34, 197, 94, 0.15)",
      color: "#86efac",
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-comment": {
      backgroundColor: "rgba(234, 179, 8, 0.15)", // yellow-500/15
      color: "#fde68a", // yellow-200
      borderRadius: "2px",
      padding: "0 1px",
    },
    ".cm-criticmark-highlight": {
      backgroundColor: "rgba(168, 85, 247, 0.15)", // purple-500/15
      color: "#d8b4fe", // purple-300
